import React, { useState } from "react";
import Result from "./Result";

const preguntas = [
  "Cuéntame un poco sobre ti.",
  "¿Por qué te interesa este puesto de desarrollador?",
  "¿Cuál consideras que ha sido tu mayor logro profesional?",
  "¿Cómo manejas situaciones de presión en el trabajo?",
  "¿Prefieres trabajar solo o en equipo? ¿Por qué?",
  "¿Dónde te ves profesionalmente dentro de 5 años?",
  "¿Por qué deberíamos contratarte para este puesto?",
  "¿Tienes experiencia previa relacionada con este tipo de trabajo?",
];

function QuestionForm() {
  const [respuestas, setRespuestas] = useState(
    preguntas.map((pregunta) => ({
      pregunta,
      texto: "",
      puntaje_manual: "",
      comentario_manual: "",
    }))
  );

  const [mostrarResultados, setMostrarResultados] = useState(false);

  const handleChange = (index, campo, valor) => {
    const nuevasRespuestas = [...respuestas];
    nuevasRespuestas[index][campo] = valor;
    setRespuestas(nuevasRespuestas);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setMostrarResultados(true);
  };

  return (
    <div>
      <h1>📝 Formulario de Entrevista</h1>
      {!mostrarResultados ? (
        <form onSubmit={handleSubmit}>
          {respuestas.map((respuesta, index) => (
            <div key={index} style={{ marginBottom: "1.5rem" }}>
              <p><strong>{respuesta.pregunta}</strong></p>
              <textarea
                value={respuesta.texto}
                onChange={(e) => handleChange(index, "texto", e.target.value)}
                rows={3}
                style={{ width: "100%" }}
                placeholder="Respuesta del postulante"
              />
              <br />
              <label>
                Puntuación del entrevistador (0 a 2):{" "}
                <input
                  type="number"
                  min="0"
                  max="2"
                  value={respuesta.puntaje_manual}
                  onChange={(e) => handleChange(index, "puntaje_manual", e.target.value)}
                />
              </label>
              <br />
              <label>
                Comentario del entrevistador:{" "}
                <input
                  type="text"
                  value={respuesta.comentario_manual}
                  onChange={(e) => handleChange(index, "comentario_manual", e.target.value)}
                  style={{ width: "100%" }}
                />
              </label>
            </div>
          ))}
          <button type="submit">📊 Evaluar respuestas</button>
        </form>
      ) : (
        <Result respuestas={respuestas} />
      )}
    </div>
  );
}

export default QuestionForm;
